('poulet_yassa_guinean', 'Poulet Yassa', 210, 22.0, 8.0, 10.0, 1.0, 3.0, 300, NULL, 'research', ARRAY['poulet yassa', 'yassa au poulet', 'chicken yassa'], 'traditional', NULL, 1, 'GN', 'Marinated chicken braised with caramelized onions, lemon juice, and mustard. Originally from Casamance region, widely adopted across Guinea as a festive dish.', TRUE),
('maafe_poulet_guinean', 'Maafe Poulet', 245, 18.0, 10.0, 16.0, 2.5, 4.0, 350, NULL, 'research', ARRAY['maafe poulet', 'mafé', 'groundnut chicken stew', 'sauce arachide poulet'], 'traditional', NULL, 1, 'GN', 'Chicken groundnut stew simmered in a rich peanut-tomato sauce with vegetables. A staple across West Africa, maafe in Guinea is enriched with local spices and often served with rice or fonio.', TRUE),
('kedjenou_de_poulet_guinean', 'Kedjenou de Poulet', 195, 24.0, 5.0, 9.0, 1.5, 3.0, 300, NULL, 'research', ARRAY['kedjenou de poulet', 'kédjénou', 'canari chicken'], 'traditional', NULL, 1, 'GN', 'Slow-cooked chicken stew sealed in a terra cotta pot (canari) with vegetables and spices, steamed in its own juices. A Guinean forest region specialty requiring no added water.', TRUE),
('thieboudienne_guineen_guinean', 'Thiéboudienne Guinéen', 220, 14.0, 28.0, 7.0, 2.0, 2.5, 400, NULL, 'research', ARRAY['thiéboudienne guinéen', 'thieb bou dien', 'riz au poisson'], 'traditional', NULL, 1, 'GN', 'Rice cooked in tomato-fish broth with stuffed whole fish and vegetables. Guinea''s coastal adaptation of the Senegalese classic, often using capitaine or tilapia.', TRUE),
('tilapia_grille_guinean', 'Tilapia Grillé', 168, 26.0, 0.0, 7.0, 0.0, 0.0, 300, 350, 'research', ARRAY['tilapia grillé', 'tilapia braisé', 'grilled tilapia'], 'seafood', NULL, 1, 'GN', 'Whole tilapia grilled over charcoal with a rub of onion, garlic, chili, and local spices. Common street food along Guinea''s rivers and coast, served with attieke or rice.', TRUE),
('capitaine_grille_guinean', 'Capitaine Grillé', 172, 27.0, 0.0, 7.5, 0.0, 0.0, 350, 400, 'research', ARRAY['capitaine grillé', 'nile perch grillé', 'poisson capitaine'], 'seafood', NULL, 1, 'GN', 'Grilled Nile perch (capitaine) seasoned with citrus, garlic, and hot pepper. A prized fish in Guinean markets, often the centerpiece of celebratory meals along the Niger tributaries.', TRUE),
('poisson_braise_a_la_sauce_tomate_guinean', 'Poisson Braisé à la Sauce Tomate', 185, 24.0, 6.0, 8.0, 1.5, 4.0, 300, NULL, 'research', ARRAY['poisson braisé à la sauce tomate', 'fish in tomato sauce', 'poisson sauce tomate'], 'seafood', NULL, 1, 'GN', 'Charcoal-grilled fish smothered in a spiced fresh tomato sauce with onions and Scotch bonnet pepper. A ubiquitous preparation throughout coastal and riverside Guinea.', TRUE),
('poisson_fume_en_sauce_guinean', 'Poisson Fumé en Sauce', 198, 28.0, 5.0, 8.5, 1.0, 2.0, 250, NULL, 'research', ARRAY['poisson fumé en sauce', 'smoked fish stew', 'sauce poisson fumé'], 'seafood', NULL, 1, 'GN', 'Smoked dried fish rehydrated and cooked in a piquant onion-tomato sauce. Smoking preserves fish for inland trade routes throughout Guinea; this preparation is essential in forest region cooking.', TRUE),
('maafe_viande_de_boeuf_guinean', 'Maafe Viande de Boeuf', 260, 20.0, 10.0, 17.0, 2.0, 4.0, 350, NULL, 'research', ARRAY['maafe viande de boeuf', 'groundnut beef stew', 'mafé boeuf'], 'traditional', NULL, 1, 'GN', 'Beef groundnut stew with tomato paste and root vegetables. In the Fouta Djallon highlands, beef maafe is preferred over chicken versions, reflecting Fula herding traditions.', TRUE),
('sauce_feuilles_de_patate_guinean', 'Sauce Feuilles de Patate', 175, 15.0, 8.0, 10.0, 3.0, 2.0, 300, NULL, 'research', ARRAY['sauce feuilles de patate', 'sweet potato leaf stew', 'sauce feuilles'], 'traditional', NULL, 1, 'GN', 'Sweet potato leaf stew with smoked fish or beef, palm oil, and ground crayfish. A forest region staple rich in iron and protein, reflecting Guinea''s abundant green leafy vegetable use.', TRUE),
('poulet_roti_aux_epices_guineennes_guinean', 'Poulet Rôti aux Épices Guinéennes', 220, 26.0, 2.0, 12.0, 0.5, 1.0, 280, NULL, 'research', ARRAY['poulet rôti aux épices guinéennes', 'spiced roast chicken', 'poulet épicé'], 'poultry', NULL, 1, 'GN', 'Whole roasted chicken rubbed with a paste of ginger, garlic, grains of selim, and palm oil. Festive preparation for weddings and Tabaski celebrations in Guinea.', TRUE),
('soupe_de_poisson_guineenne_guinean', 'Soupe de Poisson Guinéenne', 145, 18.0, 8.0, 5.0, 1.5, 2.0, 400, NULL, 'research', ARRAY['soupe de poisson guinéenne', 'fish soup', 'bouillon de poisson'], 'soups', NULL, 1, 'GN', 'Light broth-based fish soup with yam, cassava, and aromatic herbs. Prepared along the Guinean coast and along the Niger River, often sold at morning markets as a restorative meal.', TRUE),
('soupe_de_viande_aux_legumes_guinean', 'Soupe de Viande aux Légumes', 155, 16.0, 10.0, 6.0, 2.0, 3.0, 400, NULL, 'research', ARRAY['soupe de viande aux légumes', 'meat vegetable soup', 'bouillon de viande'], 'soups', NULL, 1, 'GN', 'Meat and vegetable soup with okra, tomatoes, and leafy greens. A daily household soup in Conakry and interior towns, reflecting the mixed culinary heritage of Guinea''s diverse ethnic groups.', TRUE),
('brochettes_de_boeuf_guinean', 'Brochettes de Boeuf', 235, 28.0, 2.0, 13.0, 0.0, 1.0, 200, 25, 'research', ARRAY['brochettes de boeuf', 'beef skewers', 'suya-style beef'], 'meat', NULL, 1, 'GN', 'Grilled beef skewers seasoned with onion, spices, and groundnut oil. A popular street food in Conakry and Kankan, sold by roadside vendors especially during evening hours.', TRUE),
('brochettes_de_poulet_guinean', 'Brochettes de Poulet', 195, 26.0, 2.0, 9.5, 0.0, 1.0, 180, 25, 'research', ARRAY['brochettes de poulet', 'chicken skewers', 'brochettes poulet'], 'poultry', NULL, 1, 'GN', 'Chicken skewers marinated in ginger, garlic, and citrus then grilled over charcoal. Sold alongside beef brochettes at street stalls throughout urban Guinea.', TRUE),
('capitaine_en_sauce_palme_guinean', 'Capitaine en Sauce Palme', 255, 22.0, 4.0, 17.0, 1.0, 1.5, 300, NULL, 'research', ARRAY['capitaine en sauce palme', 'capitaine palm oil', 'perch palm stew'], 'seafood', NULL, 1, 'GN', 'Nile perch braised in red palm oil sauce with tomatoes, onions, and chili. Palm oil is integral to Guinean cooking, lending richness and color to this riverside specialty.', TRUE),
('poulet_dg_guinean', 'Poulet DG', 230, 22.0, 12.0, 11.0, 2.0, 4.0, 350, NULL, 'research', ARRAY['poulet dg', 'dg chicken', 'poulet directeur général'], 'poultry', NULL, 1, 'GN', 'Directeur Général chicken — fried chicken sautéed with plantain, bell peppers, tomatoes, and spices. A prestigious urban dish associated with the elite, widely served in Conakry restaurants.', TRUE),
('boeuf_braise_guinean', 'Boeuf Braisé', 242, 26.0, 2.0, 14.0, 0.0, 1.0, 250, NULL, 'research', ARRAY['boeuf braisé', 'braised beef', 'boeuf grillé'], 'meat', NULL, 1, 'GN', 'Charcoal-grilled beef cuts marinated in spiced onion paste. A common preparation at Guinean maquis (open-air restaurants), served with fried plantain or rice.', TRUE),
('agneau_au_maafe_guinean', 'Agneau au Maafe', 270, 19.0, 10.0, 18.0, 2.0, 3.5, 350, NULL, 'research', ARRAY['agneau au maafe', 'lamb groundnut stew', 'mafé agneau'], 'meat', NULL, 1, 'GN', 'Lamb groundnut stew with root vegetables. Lamb versions of maafe are especially popular during Islamic celebrations such as Tabaski (Eid al-Adha) in predominantly Muslim Guinea.', TRUE),
('muton_yassa_guinean', 'Muton Yassa', 215, 21.0, 8.0, 11.0, 1.0, 3.0, 300, NULL, 'research', ARRAY['muton yassa', 'yassa mouton', 'lamb yassa'], 'meat', NULL, 1, 'GN', 'Mutton braised with caramelized onions and lemon, the lamb adaptation of yassa. Prepared in large quantities for Tabaski feasts when lamb is the central sacrificial animal.', TRUE),
('porc_sauce_graine_guinean', 'Porc Sauce Graine', 290, 20.0, 5.0, 22.0, 1.5, 1.0, 300, NULL, 'research', ARRAY['porc sauce graine', 'pork palm kernel stew', 'porc sauce palm'], 'meat', NULL, 1, 'GN', 'Pork in palm kernel oil sauce, a specialty of Guinea''s Christian and animist forest communities. Sauce graine (from palm nuts) is slow-extracted and lends a distinctive nutty depth.', TRUE),
('viande_de_brousse_fumee_guinean', 'Viande de Brousse Fumée', 210, 32.0, 0.0, 9.0, 0.0, 0.0, 150, NULL, 'research', ARRAY['viande de brousse fumée', 'smoked game meat', 'viande de chasse fumée'], 'game', NULL, 1, 'GN', 'Smoked bushmeat from forest antelope or cane rat, traded along forest region routes. Smoking is the primary preservation method; smoked bushmeat is highly prized for its intense flavor.', TRUE),
('agouti_en_sauce_guinean', 'Agouti en Sauce', 200, 28.0, 4.0, 9.0, 1.0, 2.0, 250, NULL, 'research', ARRAY['agouti en sauce', 'grasscutter stew', 'rat de gambie en sauce'], 'game', NULL, 1, 'GN', 'Cane rat (agouti/grass cutter) braised in tomato and onion sauce. Agouti is the most consumed bushmeat in Guinea''s forest region, considered a luxury protein at celebrations.', TRUE),
('porc_epic_braise_guinean', 'Porc-Épic Braisé', 195, 27.0, 2.0, 9.0, 0.0, 1.0, 250, NULL, 'research', ARRAY['porc-épic braisé', 'braised porcupine', 'hérisson braisé'], 'game', NULL, 1, 'GN', 'Braised porcupine meat, a delicacy in Guinea''s forested N''Zérékoré region. The quills are carefully removed before cooking; the meat is prized for its rich, slightly gamey flavor.', TRUE),
('singe_fume_guinean', 'Singe Fumé', 188, 30.0, 0.0, 7.5, 0.0, 0.0, 150, NULL, 'research', ARRAY['singe fumé', 'smoked primate', 'viande de singe'], 'game', NULL, 1, 'GN', 'Smoked monkey meat, consumed in Guinea''s deep forest communities as a traditional protein source. Its trade raises conservation concerns, but it remains culturally significant in rural areas.', TRUE),
('antilope_en_daube_guinean', 'Antilope en Daube', 185, 29.0, 3.0, 6.5, 0.5, 1.5, 250, NULL, 'research', ARRAY['antilope en daube', 'braised antelope', 'daube d''antilope'], 'game', NULL, 1, 'GN', 'Forest antelope slow-cooked with aromatic vegetables in a rich braising sauce. Antelope hunting is a traditional practice among Kpelle and Toma communities in Guinea''s forest region.', TRUE),
('varan_grille_guinean', 'Varan Grillé', 160, 28.0, 0.0, 5.5, 0.0, 0.0, 200, NULL, 'research', ARRAY['varan grillé', 'grilled monitor lizard', 'lézard grillé'], 'game', NULL, 1, 'GN', 'Grilled monitor lizard (varan), consumed in rural forest and savanna communities as a lean protein source. Considered a bush delicacy, often traded at rural markets.', TRUE),
('crocodile_en_sauce_piquante_guinean', 'Crocodile en Sauce Piquante', 170, 27.0, 3.0, 5.5, 0.5, 1.5, 250, NULL, 'research', ARRAY['crocodile en sauce piquante', 'spicy crocodile stew', 'crocodile piquant'], 'game', NULL, 1, 'GN', 'Crocodile tail meat braised in spicy tomato sauce. A rare delicacy found in communities near Guinea''s larger rivers; crocodile meat is lean and high in protein.', TRUE),
('pintade_rotie_guinean', 'Pintade Rôtie', 200, 25.0, 1.0, 11.0, 0.0, 0.5, 280, NULL, 'research', ARRAY['pintade rôtie', 'roasted guinea fowl', 'pintade grillée'], 'poultry', NULL, 1, 'GN', 'Roasted guinea fowl, one of Guinea''s most traditional poultry preparations. Guinea fowl are raised domestically throughout the country and considered a superior alternative to chicken.', TRUE),
('pintade_au_maafe_guinean', 'Pintade au Maafe', 240, 22.0, 9.0, 14.0, 2.0, 3.0, 350, NULL, 'research', ARRAY['pintade au maafe', 'guinea fowl groundnut stew', 'mafé pintade'], 'poultry', NULL, 1, 'GN', 'Guinea fowl in peanut groundnut sauce. This prestigious version of maafe replaces chicken with the more prized guinea fowl, typically reserved for honored guests.', TRUE),
('canard_aux_oignons_guinean', 'Canard aux Oignons', 250, 20.0, 7.0, 16.0, 1.0, 4.0, 300, NULL, 'research', ARRAY['canard aux oignons', 'duck with onions', 'canard braisé'], 'poultry', NULL, 1, 'GN', 'Duck braised with caramelized onions and citrus. Duck farming exists in Guinea''s lowland areas; this preparation borrows from yassa techniques applied to the richer-flavored bird.', TRUE),
('dinde_farcie_guineenne_guinean', 'Dinde Farcie Guinéenne', 220, 24.0, 8.0, 10.0, 1.5, 2.0, 350, NULL, 'research', ARRAY['dinde farcie guinéenne', 'stuffed turkey', 'turkey guinean style'], 'poultry', NULL, 1, 'GN', 'Stuffed turkey prepared for major festivities; the stuffing includes rice, raisins, onions, and local spices. A celebration dish at Christmas and New Year in Guinea''s urban Christian households.', TRUE),
('pigeon_en_sauce_graine_guinean', 'Pigeon en Sauce Graine', 215, 22.0, 5.0, 13.0, 1.5, 1.0, 280, NULL, 'research', ARRAY['pigeon en sauce graine', 'squab palm sauce', 'pigeonneau sauce graine'], 'poultry', NULL, 1, 'GN', 'Squab (young pigeon) in palm kernel sauce. Pigeon is raised in many Guinean households; sauce graine adds intense palm flavor to this small but richly flavored bird.', TRUE),
('crevettes_sautees_a_lail_guinean', 'Crevettes Sautées à l''Ail', 148, 22.0, 3.0, 5.5, 0.0, 1.0, 200, NULL, 'research', ARRAY['crevettes sautées à l''ail', 'garlic shrimp', 'crevettes ail'], 'seafood', NULL, 1, 'GN', 'Shrimp sautéed with garlic, fresh tomato, and chili. Guinea''s Atlantic coast yields abundant shrimp; garlic shrimp is a staple preparation in Conakry''s coastal neighborhoods.', TRUE),
('crevettes_en_sauce_tomate_guinean', 'Crevettes en Sauce Tomate', 155, 20.0, 8.0, 5.0, 1.5, 4.0, 250, NULL, 'research', ARRAY['crevettes en sauce tomate', 'shrimp tomato stew', 'sauce crevettes'], 'seafood', NULL, 1, 'GN', 'Shrimp braised in spiced tomato sauce with onions. A popular sauce for serving over rice or fonio, especially in Conakry and Boké prefecture''s coastal fishing communities.', TRUE),
('langouste_grillee_guinean', 'Langouste Grillée', 112, 22.0, 0.5, 2.5, 0.0, 0.0, 300, 500, 'research', ARRAY['langouste grillée', 'grilled lobster', 'homard grillé'], 'seafood', NULL, 1, 'GN', 'Grilled spiny lobster from Guinea''s Atlantic coast, halved and brushed with garlic butter and citrus. A prestige seafood item served in Conakry''s upscale restaurants and at fishing festivals.', TRUE),
('crabes_farcis_guinean', 'Crabes Farcis', 165, 18.0, 6.0, 8.0, 0.5, 1.5, 250, 200, 'research', ARRAY['crabes farcis', 'stuffed crabs', 'crabes gratinés'], 'seafood', NULL, 1, 'GN', 'Stuffed crabs with a filling of crabmeat, onions, herbs, and breadcrumbs, then baked or fried. Atlantic blue crabs are trapped along Guinea''s mangrove estuaries.', TRUE),
('barracuda_grille_guinean', 'Barracuda Grillé', 175, 28.0, 0.0, 7.0, 0.0, 0.0, 300, NULL, 'research', ARRAY['barracuda grillé', 'grilled barracuda', 'brochet de mer grillé'], 'seafood', NULL, 1, 'GN', 'Grilled Atlantic barracuda seasoned with lime, hot pepper, and garlic. A popular catch along Guinea''s coast; the firm white flesh holds up well to high-heat grilling.', TRUE),
('sole_frite_guinean', 'Sole Frite', 182, 22.0, 4.0, 9.0, 0.0, 0.0, 250, 300, 'research', ARRAY['sole frite', 'fried sole', 'filet de sole frit'], 'seafood', NULL, 1, 'GN', 'Pan-fried sole dusted in seasoned flour and fried in palm or vegetable oil. Common preparation in coastal Guinea and Conakry restaurants; the flat fish absorbs spiced marinades well.', TRUE),
('merou_en_sauce_citron_guinean', 'Mérou en Sauce Citron', 165, 26.0, 3.0, 5.5, 0.5, 1.5, 300, NULL, 'research', ARRAY['mérou en sauce citron', 'grouper lemon sauce', 'poisson citron'], 'seafood', NULL, 1, 'GN', 'Grouper braised in a lemon-herb sauce with onions and fresh tomato. Mérou is highly prized in Guinea''s artisanal fisheries; the lemon sauce highlights its delicate white flesh.', TRUE),
('rouget_grille_guinean', 'Rouget Grillé', 155, 22.0, 0.0, 7.0, 0.0, 0.0, 250, 200, 'research', ARRAY['rouget grillé', 'grilled red mullet', 'rouget barbet grillé'], 'seafood', NULL, 1, 'GN', 'Grilled red mullet, highly aromatic due to its liver left intact during cooking. Traditional Guinean coastal fishermen consider rouget best grilled whole over hardwood coals.', TRUE),
('calamar_frit_guinean', 'Calamar Frit', 175, 18.0, 8.0, 8.0, 0.0, 0.5, 200, NULL, 'research', ARRAY['calamar frit', 'fried squid', 'encornets frits'], 'seafood', NULL, 1, 'GN', 'Fried calamari rings seasoned with garlic and spices. Squid is increasingly common in Conakry''s coastal restaurants; fried preparation is adapted from Portuguese-influenced Guinean coastal cooking.', TRUE),
('sauce_gombo_au_poisson_guinean', 'Sauce Gombo au Poisson', 165, 16.0, 8.0, 9.0, 3.0, 2.5, 350, NULL, 'research', ARRAY['sauce gombo au poisson', 'okra fish soup', 'soupe gombo poisson'], 'soups', NULL, 1, 'GN', 'Okra soup cooked with fish and palm oil. The mucilaginous okra thickens the sauce naturally; this preparation is common across Guinea''s coastal and interior communities.', TRUE),
('sauce_gombo_au_poulet_guinean', 'Sauce Gombo au Poulet', 175, 17.0, 8.0, 10.0, 3.0, 2.5, 350, NULL, 'research', ARRAY['sauce gombo au poulet', 'chicken okra stew', 'sauce gombo poulet'], 'soups', NULL, 1, 'GN', 'Okra stew with chicken and smoked fish. The combination of fresh and smoked proteins creates depth of flavor typical of Guinean homestyle cooking.', TRUE),
('soupe_kandia_guinean', 'Soupe Kandia', 290, 14.0, 8.0, 24.0, 2.5, 1.5, 350, NULL, 'research', ARRAY['soupe kandia', 'palm kernel soup', 'soupe aux noix de palme'], 'soups', NULL, 1, 'GN', 'Rich palm kernel cream soup with smoked fish and various meats. Kandia is one of Guinea''s most labor-intensive traditional dishes; the palm nuts are pounded and boiled to extract cream.', TRUE),
('bouillon_de_poule_locale_guinean', 'Bouillon de Poule Locale', 85, 12.0, 3.0, 3.0, 0.5, 1.0, 400, NULL, 'research', ARRAY['bouillon de poule locale', 'local chicken broth', 'bouillon poulet fermier'], 'soups', NULL, 1, 'GN', 'Clear free-range chicken broth simmered with local herbs, ginger, and root vegetables. In Guinean culture, this restorative broth is given to the ill, postpartum women, and the elderly.', TRUE),
('sauce_tigadeguena_guinean', 'Sauce Tigadèguèna', 255, 16.0, 10.0, 18.0, 2.5, 3.0, 350, NULL, 'research', ARRAY['sauce tigadèguèna', 'tigadène', 'malian groundnut sauce'], 'traditional', NULL, 1, 'GN', 'Malian-influenced groundnut sauce (tigadèguèna) with meat and vegetables, common in northeastern Guinea''s Mandinka communities near the Mali border. Served over tô (millet porridge) or rice.', TRUE),
('poulet_fume_en_sauce_guinean', 'Poulet Fumé en Sauce', 205, 26.0, 5.0, 9.5, 1.0, 2.0, 300, NULL, 'research', ARRAY['poulet fumé en sauce', 'smoked chicken stew', 'poulet boucanné sauce'], 'poultry', NULL, 1, 'GN', 'Smoked chicken rehydrated and cooked in a tomato-onion sauce. Smoking chicken is traditional in rural Guinea for preservation; the smoky flavor is prized and smoked chicken commands premium prices.', TRUE),
('cotelettes_de_mouton_grillees_guinean', 'Côtelettes de Mouton Grillées', 245, 22.0, 0.0, 17.0, 0.0, 0.0, 200, 80, 'research', ARRAY['côtelettes de mouton grillées', 'grilled lamb chops', 'chops de mouton'], 'meat', NULL, 1, 'GN', 'Grilled lamb chops marinated in ginger, garlic, and local spices. Lamb is central to Guinean Islamic celebrations; quality chops from Fouta Djallon upland sheep are especially prized.', TRUE),
('foie_de_boeuf_saute_guinean', 'Foie de Boeuf Sauté', 175, 23.0, 5.0, 7.0, 0.0, 2.0, 200, NULL, 'research', ARRAY['foie de boeuf sauté', 'sautéed liver', 'foie à la lyonnaise africaine'], 'meat', NULL, 1, 'GN', 'Sautéed beef liver with onions and tomatoes. Organ meats are valued throughout Guinea for their affordability and nutrient density; liver is often sold fresh at morning butcher stalls.', TRUE),
('tripes_a_la_guineenne_guinean', 'Tripes à la Guinéenne', 145, 18.0, 3.0, 7.0, 0.5, 1.0, 300, NULL, 'research', ARRAY['tripes à la guinéenne', 'beef tripe stew', 'abats de boeuf'], 'meat', NULL, 1, 'GN', 'Slow-cooked beef tripe with onions, pepper, and local herbs. Tripe preparation requires hours of boiling; it is a communal cooking project typical of large family gatherings.', TRUE),
('tete_de_mouton_braisee_guinean', 'Tête de Mouton Braisée', 180, 20.0, 2.0, 10.0, 0.0, 0.5, 300, NULL, 'research', ARRAY['tête de mouton braisée', 'braised sheep head', 'tête de mouton'], 'meat', NULL, 1, 'GN', 'Braised whole sheep''s head, a festive dish prepared after Tabaski slaughter. Every part is consumed, reflecting the Guinean tradition of zero-waste butchery during Islamic festivals.', TRUE),
('queue_de_boeuf_mijotee_guinean', 'Queue de Boeuf Mijotée', 220, 20.0, 3.0, 14.0, 0.5, 1.0, 350, NULL, 'research', ARRAY['queue de boeuf mijotée', 'oxtail stew', 'ragoût de queue de boeuf'], 'meat', NULL, 1, 'GN', 'Slow-braised oxtail with root vegetables and spices. The collagen in oxtail creates a naturally thick, gelatinous sauce; this hearty preparation is associated with special occasions.', TRUE),
('curs_de_poulet_sautes_guinean', 'Cœurs de Poulet Sautés', 185, 26.0, 2.0, 8.5, 0.0, 0.5, 200, NULL, 'research', ARRAY['cœurs de poulet sautés', 'chicken hearts', 'abats de poulet'], 'poultry', NULL, 1, 'GN', 'Sautéed chicken hearts with onions, garlic, and spices. Chicken offal is sold cheaply at Guinean markets and prepared as economical but protein-rich everyday dishes.', TRUE),
('gesiers_de_poulet_en_sauce_guinean', 'Gésiers de Poulet en Sauce', 165, 22.0, 4.0, 7.0, 0.5, 1.5, 250, NULL, 'research', ARRAY['gésiers de poulet en sauce', 'chicken gizzard stew', 'gizzards tomate'], 'poultry', NULL, 1, 'GN', 'Chicken gizzards braised in tomato sauce. Gizzards require long cooking to become tender; this economical dish is popular at Guinean street stalls and local restaurants.', TRUE),
('poisson_sale_sauce_legumes_guinean', 'Poisson Salé Sauce Légumes', 175, 22.0, 7.0, 7.5, 2.0, 3.0, 300, NULL, 'research', ARRAY['poisson salé sauce légumes', 'salt fish stew', 'poisson sec sauce'], 'seafood', NULL, 1, 'GN', 'Salt-dried fish rehydrated and cooked with mixed vegetables. Salt fish is an important preserved protein in Guinea''s interior markets where fresh fish supply is unreliable.', TRUE),
('crevettes_sechees_en_sauce_guinean', 'Crevettes Séchées en Sauce', 145, 20.0, 5.0, 5.5, 1.0, 2.0, 250, NULL, 'research', ARRAY['crevettes séchées en sauce', 'dried shrimp sauce', 'sauce yéyé'], 'seafood', NULL, 1, 'GN', 'Dried shrimp cooked in a tomato-palm oil sauce. Dried shrimp (yéyé) is traded from the coast inland; its intense umami flavor is essential to many Guinean stews and rice dishes.', TRUE),
('sardines_fraiches_grillees_guinean', 'Sardines Fraîches Grillées', 172, 20.0, 0.0, 10.0, 0.0, 0.0, 200, 60, 'research', ARRAY['sardines fraîches grillées', 'grilled fresh sardines', 'sardines au charbon'], 'seafood', NULL, 1, 'GN', 'Fresh sardines grilled over charcoal with sea salt and citrus. Sardines are one of the most affordable fish along Guinea''s Atlantic coast; abundant sardine runs support coastal livelihoods.', TRUE),
('maquereau_braise_guinean', 'Maquereau Braisé', 195, 20.0, 0.0, 13.0, 0.0, 0.0, 250, 250, 'research', ARRAY['maquereau braisé', 'braised mackerel', 'maquereau grillé'], 'seafood', NULL, 1, 'GN', 'Whole braised mackerel marinated in lemon, garlic, and spices. Atlantic mackerel is abundant off Guinea''s coast and high in omega-3 fatty acids; braising keeps the oily fish moist.', TRUE),
('thon_en_daube_guinean', 'Thon en Daube', 182, 26.0, 4.0, 6.5, 0.5, 2.0, 300, NULL, 'research', ARRAY['thon en daube', 'braised tuna', 'thon mijoté'], 'seafood', NULL, 1, 'GN', 'Braised tuna steak with tomatoes, onions, and herbs. Atlantic yellowfin tuna passes through Guinea''s exclusive economic zone; fresh tuna is reserved for high-quality preparations.', TRUE),
('poisson_chat_en_sauce_piquante_guinean', 'Poisson Chat en Sauce Piquante', 168, 22.0, 5.0, 7.0, 1.0, 2.0, 300, NULL, 'research', ARRAY['poisson chat en sauce piquante', 'catfish pepper stew', 'silure piquant'], 'seafood', NULL, 1, 'GN', 'Catfish (silure) in spicy chili and tomato sauce. Catfish is widely fished in Guinea''s rivers and is particularly popular in inland communities; its robust flavor pairs well with hot sauces.', TRUE),
('carpe_en_sauce_gombo_guinean', 'Carpe en Sauce Gombo', 175, 20.0, 7.0, 8.0, 2.5, 2.0, 300, NULL, 'research', ARRAY['carpe en sauce gombo', 'carp okra stew', 'carpe gombo'], 'seafood', NULL, 1, 'GN', 'Carp cooked in okra sauce. Carp is farmed and caught in Guinea''s rivers; the mucilaginous okra sauce complements the fish''s earthier flavor in this traditional riverside preparation.', TRUE),
('bonga_fume_en_sauce_guinean', 'Bonga Fumé en Sauce', 185, 24.0, 4.0, 8.5, 1.0, 2.0, 250, NULL, 'research', ARRAY['bonga fumé en sauce', 'smoked bonga sauce', 'sardinelle fumée'], 'seafood', NULL, 1, 'GN', 'Smoked bonga fish (sardinella) cooked in tomato-onion sauce. Bonga is the most commercially important fish in Guinea; smoked bonga is an essential flavoring agent throughout Guinean cooking.', TRUE),
('yetou_roti_guinean', 'Yétou Rôti', 195, 22.0, 0.0, 12.0, 0.0, 0.0, 300, NULL, 'research', ARRAY['yétou rôti', 'roasted dried fish', 'yétou grillé'], 'seafood', NULL, 1, 'GN', 'Roasted dried yétou fish, a preparation traditional to Guinea''s coastal Soussou fishermen. Yétou is fermented-salted before drying, giving it an intensely savory umami character.', TRUE),
('ragout_de_cabri_guinean', 'Ragoût de Cabri', 215, 22.0, 5.0, 12.0, 1.0, 2.0, 300, NULL, 'research', ARRAY['ragoût de cabri', 'goat stew', 'ragoût de chèvre'], 'meat', NULL, 1, 'GN', 'Goat meat stew with tomatoes, onions, and spices. Goat is the most commonly slaughtered animal in Guinea; goat stew is a standard celebration dish across all ethnic groups.', TRUE),
('cabri_en_yassa_guinean', 'Cabri en Yassa', 200, 21.0, 8.0, 10.0, 1.0, 3.5, 300, NULL, 'research', ARRAY['cabri en yassa', 'goat yassa', 'yassa de cabri'], 'meat', NULL, 1, 'GN', 'Goat yassa — marinated goat pieces braised with caramelized onions and mustard. An adaptation of the yassa technique applied to goat, popular in urban Guinean restaurants.', TRUE),
('poulet_a_la_biere_guinean', 'Poulet à la Bière', 210, 22.0, 5.0, 11.0, 0.5, 2.5, 300, NULL, 'research', ARRAY['poulet à la bière', 'beer-braised chicken', 'poulet à la flag'], 'poultry', NULL, 1, 'GN', 'Chicken braised in local beer with onions and herbs. This dish reflects Guinea''s small urban breweries and the influence of French-colonial techniques on local cooking.', TRUE),
('sauce_pistache_au_poulet_guinean', 'Sauce Pistache au Poulet', 265, 19.0, 6.0, 19.0, 2.5, 1.5, 300, NULL, 'research', ARRAY['sauce pistache au poulet', 'egusi chicken sauce', 'sauce graines de courge'], 'traditional', NULL, 1, 'GN', 'Chicken in egusi (melon seed) sauce — not pistachios as the name implies. Egusi seeds are ground into a paste that thickens the sauce; this preparation is common in forest region Guinea.', TRUE),
('sauce_pistache_au_poisson_guinean', 'Sauce Pistache au Poisson', 255, 20.0, 6.0, 18.0, 2.5, 1.5, 300, NULL, 'research', ARRAY['sauce pistache au poisson', 'egusi fish sauce', 'poisson sauce pistache'], 'seafood', NULL, 1, 'GN', 'Fish in egusi seed sauce. The ground melon seeds add protein and a rich, slightly bitter flavor to the sauce; smoked fish is often combined with fresh fish in this preparation.', TRUE),
('soupe_legere_de_boeuf_guinean', 'Soupe Légère de Boeuf', 125, 15.0, 5.0, 5.0, 1.0, 2.0, 400, NULL, 'research', ARRAY['soupe légère de boeuf', 'light beef broth', 'bouillon léger boeuf'], 'soups', NULL, 1, 'GN', 'Light beef broth with vegetables, a restorative soup served for breakfast in Guinean highland households. The Fouta Djallon mountains produce good beef cattle, making this a highland staple.', TRUE),
('poulet_moambe_guinean', 'Poulet Moambé', 275, 20.0, 4.0, 21.0, 1.5, 1.5, 300, NULL, 'research', ARRAY['poulet moambé', 'moambé chicken', 'chicken palm butter'], 'poultry', NULL, 1, 'GN', 'Chicken moambé in palm butter sauce, influenced by Central African cooking brought through trade networks. In southern Guinea near the Sierra Leone border, this dish is associated with forest communities.', TRUE),
('thiebou_yapp_guinean', 'Thiébou Yapp', 230, 16.0, 28.0, 7.0, 1.5, 2.0, 400, NULL, 'research', ARRAY['thiébou yapp', 'lamb rice dish'], 'traditional', NULL, 1, 'GN', 'Lamb and rice dish cooked in spiced tomato broth with vegetables. The meat variation of thiéboudienne, adapted to Guinea''s highland regions where sheep are more abundant than fish.', TRUE),
('riz_gras_au_poulet_guinean', 'Riz Gras au Poulet', 210, 14.0, 28.0, 6.0, 1.0, 2.0, 400, NULL, 'research', ARRAY['riz gras au poulet', 'jollof-style chicken rice', 'riz au gras'], 'traditional', NULL, 1, 'GN', 'Fat rice with chicken — rice cooked in spiced chicken broth until each grain absorbs the rich stock. A celebratory dish for naming ceremonies and weddings throughout Guinea.', TRUE),
('riz_gras_au_poisson_guinean', 'Riz Gras au Poisson', 200, 13.0, 28.0, 5.5, 1.0, 2.0, 400, NULL, 'research', ARRAY['riz gras au poisson', 'fish rice', 'riz au poisson gras'], 'traditional', NULL, 1, 'GN', 'Rice cooked in fish broth with smoked fish and fresh tomato sauce. The coastal Soussou version of riz gras favors fish over meat, reflecting proximity to marine resources.', TRUE),
('poulet_bicyclette_grille_guinean', 'Poulet Bicyclette Grillé', 185, 27.0, 0.0, 8.5, 0.0, 0.0, 280, NULL, 'research', ARRAY['poulet bicyclette grillé', 'village chicken grilled', 'poulet fermier grillé'], 'poultry', NULL, 1, 'GN', 'Grilled free-range village chicken (called ''bicyclette'' for their lean, active bodies). These lean chickens have more intense flavor than commercial birds and are significantly more expensive.', TRUE),
('beef_suya_guineen_guinean', 'Beef Suya Guinéen', 230, 28.0, 3.0, 12.0, 0.5, 1.5, 200, NULL, 'research', ARRAY['beef suya guinéen', 'suya beef', 'viande épicée skewer'], 'meat', NULL, 1, 'GN', 'Spiced thin-sliced beef grilled on skewers, influenced by Hausa suya tradition spread through Fulani trade networks into northeastern Guinea. Coated with ground peanuts and spice mix.', TRUE),
('maafe_de_poisson_guinean', 'Maafe de Poisson', 235, 20.0, 9.0, 15.0, 2.0, 3.5, 350, NULL, 'research', ARRAY['maafe de poisson', 'fish groundnut sauce', 'mafé poisson'], 'seafood', NULL, 1, 'GN', 'Fish groundnut stew with fresh tomato and onions. The coastal version of maafe substitutes fish for meat, allowing access to this beloved sauce for communities along Guinea''s rivers.', TRUE),
('sauce_claire_au_mouton_guinean', 'Sauce Claire au Mouton', 175, 18.0, 6.0, 9.0, 1.0, 2.0, 350, NULL, 'research', ARRAY['sauce claire au mouton', 'light mutton sauce', 'sauce mouton fouta'], 'meat', NULL, 1, 'GN', 'Light sauce with mutton — a thin, herbal mutton broth-sauce common in Fouta Djallon cooking. Fula herders traditionally prepare this light stew from recently slaughtered animals.', TRUE),
('ragout_de_boeuf_aux_arachides_guinean', 'Ragoût de Boeuf aux Arachides', 260, 20.0, 8.0, 17.0, 2.0, 3.0, 350, NULL, 'research', ARRAY['ragoût de boeuf aux arachides', 'beef peanut stew', 'boeuf aux arachides'], 'meat', NULL, 1, 'GN', 'Beef stew with whole groundnuts, a variant of maafe in which whole peanuts remain in the stew for texture. Common in Malinké communities of northeastern Guinea''s Haute Guinée.', TRUE),
('poulet_sauce_citron_gingembre_guinean', 'Poulet Sauce Citron Gingembre', 195, 24.0, 5.0, 9.0, 0.5, 2.5, 300, NULL, 'research', ARRAY['poulet sauce citron gingembre', 'ginger lemon chicken', 'poulet gingembre'], 'poultry', NULL, 1, 'GN', 'Chicken braised in lemon-ginger sauce with aromatics. Ginger is extensively grown in Guinea (one of Africa''s top producers); this sauce showcases the aromatic root that is central to Guinean cooking.', TRUE),
('pintade_kedjenou_guinean', 'Pintade Kedjenou', 200, 24.0, 5.0, 10.0, 1.5, 2.5, 300, NULL, 'research', ARRAY['pintade kedjenou', 'guinea fowl kedjenou', 'kédjénou pintade'], 'poultry', NULL, 1, 'GN', 'Guinea fowl prepared kedjenou-style in a sealed earthenware pot. This variant replaces chicken with the more traditional guinea fowl; considered the original form of kedjenou.', TRUE),
('agneau_kedjenou_guinean', 'Agneau Kedjenou', 225, 22.0, 5.0, 13.0, 1.0, 2.0, 300, NULL, 'research', ARRAY['agneau kedjenou', 'lamb kedjenou', 'kédjénou agneau'], 'meat', NULL, 1, 'GN', 'Lamb slow-cooked kedjenou-style in a sealed vessel with aromatic vegetables. This forest region technique applied to lamb is a specialty of highland Guinean communities.', TRUE),
('boulettes_de_poisson_guinean', 'Boulettes de Poisson', 170, 20.0, 8.0, 7.0, 1.0, 2.0, 250, 30, 'research', ARRAY['boulettes de poisson', 'fish balls', 'kefteh de poisson'], 'seafood', NULL, 1, 'GN', 'Fish meatballs made from minced fresh fish mixed with onions, herbs, and egg, then simmered in tomato sauce. A resourceful preparation using fish scraps common in Conakry''s fishing neighborhoods.', TRUE),
('roti_de_boeuf_guineen_guinean', 'Rôti de Boeuf Guinéen', 240, 26.0, 2.0, 14.0, 0.0, 1.0, 250, NULL, 'research', ARRAY['rôti de boeuf guinéen', 'guinean roast beef', 'boeuf rôti épicé'], 'meat', NULL, 1, 'GN', 'Slow-roasted beef marinated in local spice paste including grains of selim and hot pepper. Roasting whole cuts is associated with celebrations and is performed at communal fires.', TRUE),
('soupe_kankan_guinean', 'Soupe Kankan', 165, 16.0, 9.0, 8.0, 2.0, 3.0, 400, NULL, 'research', ARRAY['soupe kankan', 'kankan meat soup', 'soupe de kankan'], 'soups', NULL, 1, 'GN', 'Meat and vegetable soup from Kankan city, Guinea''s second largest city and spiritual capital. This Malinké-style soup combines beef with local root vegetables and aromatic herbs.', TRUE),
('soupe_de_feuilles_de_manioc_guinean', 'Soupe de Feuilles de Manioc', 155, 14.0, 7.0, 9.0, 3.5, 1.5, 350, NULL, 'research', ARRAY['soupe de feuilles de manioc', 'cassava leaf stew', 'sauce feuilles manioc'], 'soups', NULL, 1, 'GN', 'Cassava leaf soup with smoked fish and palm oil, common throughout Guinea''s forest and coastal regions. Pounding cassava leaves is labor-intensive; the resulting stew is highly nutritious.', TRUE),
('poulet_au_fonio_guinean', 'Poulet au Fonio', 215, 18.0, 20.0, 8.0, 1.5, 1.0, 350, NULL, 'research', ARRAY['poulet au fonio', 'chicken with fonio', 'poulet et fonio'], 'traditional', NULL, 1, 'GN', 'Chicken served over steamed fonio grain. Fonio is Guinea''s ancient indigenous grain; this pairing is a point of national pride, promoted as a nutritious alternative to rice.', TRUE),
('viande_en_sauce_legumes_guinean', 'Viande en Sauce Légumes', 185, 18.0, 8.0, 10.0, 2.5, 3.5, 350, NULL, 'research', ARRAY['viande en sauce légumes', 'meat vegetable sauce', 'sauce viande légumes'], 'meat', NULL, 1, 'GN', 'Mixed meat in vegetable sauce with eggplant, tomatoes, and onions. A flexible daily dish adapted to whatever meat is available; the vegetable base is consistent across all Guinea regions.', TRUE),
('tilapia_en_sauce_gombo_guinean', 'Tilapia en Sauce Gombo', 170, 20.0, 7.0, 7.5, 3.0, 2.0, 300, NULL, 'research', ARRAY['tilapia en sauce gombo', 'tilapia okra stew', 'tilapia sauce gombo'], 'seafood', NULL, 1, 'GN', 'Tilapia braised in okra sauce. The combination of tilapia with okra produces a naturally thickened sauce with a distinctive texture prized in Guinean river communities.', TRUE),
('sauce_aubergine_au_poulet_guinean', 'Sauce Aubergine au Poulet', 175, 17.0, 9.0, 9.0, 3.0, 4.5, 300, NULL, 'research', ARRAY['sauce aubergine au poulet', 'eggplant chicken stew', 'sauce aubergine africaine'], 'poultry', NULL, 1, 'GN', 'Eggplant stew with chicken pieces in palm oil sauce. African eggplant varieties are small and bitter; they are salted and fried before being combined with chicken in this common Guinean preparation.', TRUE),
('poisson_a_la_nantua_guineenne_guinean', 'Poisson à la Nantua Guinéenne', 195, 22.0, 5.0, 10.0, 0.5, 2.0, 300, NULL, 'research', ARRAY['poisson à la nantua guinéenne', 'fish shrimp sauce', 'filet poisson sauce crevettes'], 'seafood', NULL, 1, 'GN', 'Fish fillets in a shrimp-enriched cream sauce, a French-influenced preparation found in Conakry''s colonial-era restaurants. Adapted to local ingredients using dried shrimp paste.', TRUE),
('boeuf_seche_pimente_guinean', 'Boeuf Séché Pimenté', 285, 40.0, 2.0, 13.0, 0.0, 0.5, 100, NULL, 'research', ARRAY['boeuf séché pimenté', 'spiced dried beef', 'viande séchée épicée'], 'meat', NULL, 1, 'GN', 'Spiced dried beef, a concentrated protein snack sold at Guinean markets. Drying beef in the harmattan winds of the savanna is a traditional preservation technique of northern Guinea.', TRUE),
('capitaine_farci_guinean', 'Capitaine Farci', 188, 25.0, 3.0, 9.0, 0.5, 1.5, 350, NULL, 'research', ARRAY['capitaine farci', 'stuffed capitaine', 'capitaine en papillote farci'], 'seafood', NULL, 1, 'GN', 'Whole capitaine fish stuffed with a mixture of onions, herbs, tomato, and spices before baking or grilling. A festive fish preparation in Guinean coastal homes for celebrations.', TRUE),
('poulet_kedjenou_aux_champignons_guinean', 'Poulet Kedjenou aux Champignons', 185, 23.0, 5.0, 9.0, 2.0, 2.5, 300, NULL, 'research', ARRAY['poulet kedjenou aux champignons', 'mushroom kedjenou', 'kédjénou champignons'], 'poultry', NULL, 1, 'GN', 'Kedjenou chicken with forest mushrooms, a specialty of Guinea''s N''Zérékoré region. Wild mushrooms gathered from the forest floor add earthy depth to this classic sealed-pot preparation.', TRUE),
('potage_de_tripes_guinean', 'Potage de Tripes', 140, 16.0, 5.0, 6.0, 1.0, 1.5, 400, NULL, 'research', ARRAY['potage de tripes', 'tripe soup', 'soupe de tripes'], 'soups', NULL, 1, 'GN', 'Tripe soup with vegetables and aromatic herbs. Market women in Guinean cities prepare and sell tripe soup (potage de tripes) from large pots as a hearty inexpensive morning meal.', TRUE),
('soupe_de_queue_de_boeuf_guinean', 'Soupe de Queue de Boeuf', 165, 17.0, 6.0, 8.5, 1.5, 2.0, 400, NULL, 'research', ARRAY['soupe de queue de boeuf', 'oxtail soup', 'soupe queue boeuf'], 'soups', NULL, 1, 'GN', 'Oxtail soup simmered for hours to extract collagen and deep beefy flavor. Sold at Guinean roadside restaurants as a restorative meal, especially during the rainy season.', TRUE),
('sauce_graine_au_poisson_guinean', 'Sauce Graine au Poisson', 285, 16.0, 6.0, 23.0, 2.0, 1.0, 350, NULL, 'research', ARRAY['sauce graine au poisson', 'fish palm kernel sauce', 'poisson sauce graine'], 'seafood', NULL, 1, 'GN', 'Fish in palm kernel cream sauce. The orange-red palm kernel cream is extracted through laborious pounding and boiling of palm nuts; this fish version is popular during harvest festivals.', TRUE),
('crevettes_grillees_piment_guinean', 'Crevettes Grillées Piment', 142, 22.0, 2.0, 5.0, 0.0, 1.0, 200, NULL, 'research', ARRAY['crevettes grillées piment', 'chili grilled shrimp', 'crevettes pimentées'], 'seafood', NULL, 1, 'GN', 'Whole shrimp grilled with chili marinade. Large tiger shrimp caught off Guinea''s coast are best prepared simply grilled; street vendors sell these by the skewer along Conakry''s beaches.', TRUE),
('poulet_pimente_conakry_guinean', 'Poulet Pimenté Conakry', 205, 24.0, 4.0, 10.0, 0.5, 2.0, 300, NULL, 'research', ARRAY['poulet pimenté conakry', 'conakry spicy chicken', 'poulet fort'], 'poultry', NULL, 1, 'GN', 'Conakry-style spicy chicken fried with Scotch bonnet peppers and onions. A popular urban street food dish in Guinea''s capital, reflecting the spicy food culture of Guinea''s coastal Soussou people.', TRUE),
('poisson_a_la_lime_et_coriandre_guinean', 'Poisson à la Lime et Coriandre', 162, 25.0, 2.0, 6.0, 0.5, 1.0, 280, NULL, 'research', ARRAY['poisson à la lime et coriandre', 'lime herb fish', 'poisson citron vert'], 'seafood', NULL, 1, 'GN', 'Grilled fish in lime and fresh herb marinade, influenced by Portuguese flavors through Guinea''s colonial history and interactions with Cape Verdean sailors along the coast.', TRUE),
('daube_de_cabri_guinean', 'Daube de Cabri', 205, 22.0, 4.0, 11.5, 0.5, 2.0, 300, NULL, 'research', ARRAY['daube de cabri', 'goat daube', 'ragoût de chèvre'], 'meat', NULL, 1, 'GN', 'Braised goat in French-inspired daube sauce with red wine substitute and vegetables. A French-colonial culinary legacy adapted with local ingredients; found in urban Guinea''s nicer restaurants.', TRUE),
('tilapia_farci_guinean', 'Tilapia Farci', 178, 23.0, 4.0, 8.0, 1.0, 2.0, 300, 400, 'research', ARRAY['tilapia farci', 'stuffed tilapia', 'tilapia farci grillé'], 'seafood', NULL, 1, 'GN', 'Whole tilapia stuffed with onion-herb mixture before grilling. Stuffed fish preparations are central to Guinean festive cooking; the stuffing bastes the fish from within during grilling.', TRUE),
('sauce_foufou_au_poulet_guinean', 'Sauce Foufou au Poulet', 225, 18.0, 12.0, 13.0, 1.5, 2.5, 350, NULL, 'research', ARRAY['sauce foufou au poulet', 'chicken foufou sauce', 'sauce pour foufou'], 'traditional', NULL, 1, 'GN', 'Spicy chicken sauce traditionally served alongside pounded cassava (foufou). The sauce for foufou must be rich enough to eat with the starchy fufu; this palm-oil-enriched version is standard.', TRUE),
('poisson_capitaine_braise_entier_guinean', 'Poisson Capitaine Braisé Entier', 175, 26.0, 2.0, 7.0, 0.0, 1.0, 400, NULL, 'research', ARRAY['poisson capitaine braisé entier', 'whole braised capitaine', 'capitaine entier'], 'seafood', NULL, 1, 'GN', 'Whole braised capitaine fish marinated overnight in herbs and spices. Serving fish whole is traditional in Guinean culture as a sign of abundance; the head is considered the most flavorful part.', TRUE),
('lapin_en_sauce_guinean', 'Lapin en Sauce', 195, 24.0, 4.0, 9.5, 0.5, 2.0, 300, NULL, 'research', ARRAY['lapin en sauce', 'rabbit stew', 'lapin sauté'], 'game', NULL, 1, 'GN', 'Rabbit in tomato-onion sauce, hunted in Guinea''s savanna regions. Wild rabbit is considered a semi-wild food; it is smaller and more flavorful than farmed varieties.', TRUE),
('perdrix_rotie_guinean', 'Perdrix Rôtie', 185, 25.0, 0.0, 9.5, 0.0, 0.0, 250, 400, 'research', ARRAY['perdrix rôtie', 'roasted partridge', 'faisan rôti'], 'game', NULL, 1, 'GN', 'Roasted partridge, a hunted game bird common in Guinea''s highland and savanna regions. Partridge is small but richly flavored; it is roasted whole on a spit over wood fire.', TRUE),
('tourterelle_grillee_guinean', 'Tourterelle Grillée', 175, 24.0, 0.0, 8.5, 0.0, 0.0, 200, 150, 'research', ARRAY['tourterelle grillée', 'grilled dove', 'pigeon sauvage grillé'], 'game', NULL, 1, 'GN', 'Grilled wild dove, hunted during migration seasons in Guinea''s open savanna. Small birds are threaded onto sticks and grilled over fire; their delicate meat requires minimal seasoning.', TRUE),
('pintade_sauce_pimentee_guinean', 'Pintade Sauce Pimentée', 210, 24.0, 5.0, 10.0, 1.0, 2.0, 300, NULL, 'research', ARRAY['pintade sauce pimentée', 'spicy guinea fowl', 'pintade pimentée'], 'poultry', NULL, 1, 'GN', 'Guinea fowl in fiery pepper sauce. Spicy guinea fowl preparations are festive dishes in Soussou communities; the bird is marinated in chili paste before cooking.', TRUE),
('capitaine_a_la_sauce_creole_guinean', 'Capitaine à la Sauce Créole', 192, 24.0, 6.0, 8.5, 1.5, 3.5, 300, NULL, 'research', ARRAY['capitaine à la sauce créole', 'creole capitaine', 'capitaine sauce créole'], 'seafood', NULL, 1, 'GN', 'Capitaine fish in a Creole-style sauce with tomatoes, bell peppers, and tropical herbs. The Creole influence reflects Guinea''s connection with French Caribbean cuisine through colonial history.', TRUE),
('crevettes_sauce_arachide_guinean', 'Crevettes Sauce Arachide', 225, 20.0, 7.0, 14.0, 1.5, 3.0, 280, NULL, 'research', ARRAY['crevettes sauce arachide', 'shrimp groundnut sauce', 'crevettes maafe'], 'seafood', NULL, 1, 'GN', 'Shrimp in groundnut sauce. This coastal-highland fusion dish brings together Guinea''s seafood and inland peanut farming traditions; found in restaurants that bridge coastal and interior cuisines.', TRUE),
('viande_de_phacochere_guinean', 'Viande de Phacochère', 185, 28.0, 0.0, 8.0, 0.0, 0.0, 250, NULL, 'research', ARRAY['viande de phacochère', 'warthog meat', 'sanglier africain'], 'game', NULL, 1, 'GN', 'Warthog meat, hunted in Guinea''s savanna zones. Warthog is considered excellent bushmeat with pork-like flavor; it is roasted or braised and is especially prized in northern Guinea.', TRUE),
('hippopotame_braise_guinean', 'Hippopotame Braisé', 175, 26.0, 0.0, 8.0, 0.0, 0.0, 200, NULL, 'research', ARRAY['hippopotame braisé', 'hippo meat', 'viande d''hippopotame'], 'game', NULL, 1, 'GN', 'Braised hippo meat, historically consumed by river communities in Guinea''s interior. While now rare due to conservation concerns, hippo meat remains a cultural memory in communities along the Niger headwaters.', TRUE),
('elephant_seche_historique_guinean', 'Éléphant Séché (Historique)', 200, 30.0, 0.0, 9.0, 0.0, 0.0, 100, NULL, 'research', ARRAY['éléphant séché (historique)', 'dried elephant meat', 'viande séchée éléphant'], 'game', NULL, 1, 'GN', 'Dried elephant meat, historically consumed after community hunts in forested Guinea. Now protected by law; this entry documents a historical food practice of forest communities rather than a current dish.', TRUE),
('buffle_en_sauce_guinean', 'Buffle en Sauce', 192, 27.0, 3.0, 8.5, 0.5, 1.5, 250, NULL, 'research', ARRAY['buffle en sauce', 'buffalo stew', 'ragoût de buffle'], 'game', NULL, 1, 'GN', 'Cape buffalo braised in tomato and spice sauce. Buffalo hunting is traditional among Malinké hunters in northeastern Guinea; the meat is tough and requires long slow cooking.', TRUE),
('poisson_electrique_fume_guinean', 'Poisson Électrique Fumé', 178, 25.0, 0.0, 8.5, 0.0, 0.0, 150, NULL, 'research', ARRAY['poisson électrique fumé', 'smoked electric catfish', 'poisson électrique'], 'seafood', NULL, 1, 'GN', 'Smoked electric catfish (malapterurus), traded in Guinea''s river markets. This large, high-voltage catfish is smoked after catching; its firm oily flesh is prized when smoked.', TRUE),
('poulet_yassa_sans_moutarde_guinean', 'Poulet Yassa sans Moutarde', 195, 22.0, 7.0, 9.5, 1.0, 3.5, 300, NULL, 'research', ARRAY['poulet yassa sans moutarde', 'mustard-free yassa', 'yassa traditionnel'], 'poultry', NULL, 1, 'GN', 'Yassa chicken made without mustard — the traditional inland Guinean version that predates European mustard''s introduction. Uses only lemon, vinegar, and abundant caramelized onions for tang.', TRUE),
('ragout_de_crevettes_fraiches_guinean', 'Ragoût de Crevettes Fraiches', 155, 20.0, 5.0, 6.5, 1.0, 2.5, 300, NULL, 'research', ARRAY['ragoût de crevettes fraiches', 'fresh shrimp stew', 'ragoût de crevettes'], 'seafood', NULL, 1, 'GN', 'Fresh shrimp stew with vegetables and herbs. Conakry''s proximity to prolific shrimp grounds means fresh shrimp is available daily; this simple stew preserves the natural sweetness.', TRUE),
('fricassee_de_poulet_guinean', 'Fricassée de Poulet', 205, 22.0, 5.0, 11.0, 0.5, 2.0, 300, NULL, 'research', ARRAY['fricassée de poulet', 'chicken fricassee', 'poulet fricassée'], 'poultry', NULL, 1, 'GN', 'Guinea-style chicken fricassee with tomatoes and local spices. The French-colonial term fricassée was adopted into Guinean cooking; local versions include palm oil and regional spices.', TRUE),
('boeuf_en_sauce_oseille_guinean', 'Boeuf en Sauce Oseille', 195, 20.0, 4.0, 11.0, 1.5, 2.5, 300, NULL, 'research', ARRAY['boeuf en sauce oseille', 'beef sorrel sauce', 'boeuf sauce oseille guinéenne'], 'meat', NULL, 1, 'GN', 'Beef in sorrel (bissap leaf) sauce with palm oil. Hibiscus leaves give this sauce a deep red color and tart flavor; the tartness complements beef in this Soussou specialty.', TRUE),
('poisson_a_la_senegalaise_guinean', 'Poisson à la Sénégalaise', 210, 22.0, 8.0, 10.0, 1.5, 3.0, 350, NULL, 'research', ARRAY['poisson à la sénégalaise', 'senegalese-style fish', 'poisson thiébou'], 'seafood', NULL, 1, 'GN', 'Fish prepared Senegalese-style with thiéboudienne spice blend, reflecting the close cultural exchange between Guinea and Senegal. Prepared with stuffed fish and rice in Conakry''s Senegalese-influenced neighborhoods.', TRUE),
('sauce_tomate_viande_hachee_guinean', 'Sauce Tomate Viande Hachée', 195, 18.0, 7.0, 11.0, 1.5, 4.5, 300, NULL, 'research', ARRAY['sauce tomate viande hachée', 'minced meat tomato sauce', 'viande hachée tomate'], 'meat', NULL, 1, 'GN', 'Minced meat in fresh tomato sauce, a quick daily preparation across Guinean urban households. Ground beef extends the protein further and cooks quickly, making it practical for city dwellers.', TRUE),
('poisson_peche_du_jour_guinean', 'Poisson Péché du Jour', 158, 26.0, 0.0, 6.0, 0.0, 0.0, 300, NULL, 'research', ARRAY['poisson péché du jour', 'catch of the day', 'poisson du jour'], 'seafood', NULL, 1, 'GN', 'Catch-of-the-day fish simply grilled or fried. Guinea''s artisanal fishermen land diverse species; the daily catch drives coastal communities'' diets more than any fixed recipe.', TRUE),
('gambas_a_la_plancha_guinean', 'Gambas à la Plancha', 118, 22.0, 1.0, 3.0, 0.0, 0.5, 200, 40, 'research', ARRAY['gambas à la plancha', 'grilled king prawns', 'crevettes géantes grillées'], 'seafood', NULL, 1, 'GN', 'Large grilled prawns cooked on a flat griddle with garlic and citrus. Spanish-influenced through Portuguese colonial connections; found in Conakry''s upscale seafood restaurants.', TRUE),
('huitres_grillees_de_guinee_guinean', 'Huîtres Grillées de Guinée', 82, 10.0, 5.0, 2.5, 0.0, 1.0, 200, 30, 'research', ARRAY['huîtres grillées de guinée', 'mangrove oysters', 'huîtres de palétuvier'], 'seafood', NULL, 1, 'GN', 'Grilled oysters from Guinea''s mangrove estuaries. Mangrove oyster harvesting is a traditional livelihood for Conakry''s Soussou fishing women; grilled oysters are sold at beach markets.', TRUE),
('poisson_braise_sauce_piment_guinean', 'Poisson Braisé Sauce Piment', 175, 24.0, 4.0, 7.5, 1.0, 2.0, 300, NULL, 'research', ARRAY['poisson braisé sauce piment', 'spicy grilled fish', 'poisson pimenté'], 'seafood', NULL, 1, 'GN', 'Grilled fish in fiery chili sauce. Guinea''s Scotch bonnet and African bird''s eye chilies create intensely hot sauces; this preparation is a test of heat tolerance at Guinea''s roadside grills.', TRUE),
('soupe_de_riz_au_poulet_guinean', 'Soupe de Riz au Poulet', 125, 10.0, 15.0, 3.0, 0.5, 1.0, 400, NULL, 'research', ARRAY['soupe de riz au poulet', 'chicken rice porridge', 'bouillie de riz poulet'], 'soups', NULL, 1, 'GN', 'Chicken rice porridge, served as a breakfast or recovery meal. Thin rice gruel with chicken pieces is given to infants, the elderly, and the sick throughout Guinea.', TRUE),
('cabri_maafe_guinean', 'Cabri Maafe', 250, 20.0, 10.0, 16.0, 2.0, 3.5, 350, NULL, 'research', ARRAY['cabri maafe', 'goat maafe', 'mafé de cabri'], 'meat', NULL, 1, 'GN', 'Goat groundnut stew. In some Guinean regions, goat maafe is preferred over lamb or beef versions; the gamey flavor of goat pairs especially well with groundnut sauce.', TRUE),
('boeuf_braise_aux_legumes_guinean', 'Boeuf Braisé aux Légumes', 210, 22.0, 7.0, 11.0, 2.0, 3.5, 350, NULL, 'research', ARRAY['boeuf braisé aux légumes', 'braised beef vegetables', 'boeuf aux légumes'], 'meat', NULL, 1, 'GN', 'Braised beef with mixed vegetables including carrots, turnips, and onions. A French-colonial inspired dish that became part of Guinean urban cooking during the colonial period.', TRUE),
('lotte_grillee_guinean', 'Lotte Grillée', 160, 26.0, 0.0, 6.0, 0.0, 0.0, 300, NULL, 'research', ARRAY['lotte grillée', 'grilled monkfish', 'baudroie grillée'], 'seafood', NULL, 1, 'GN', 'Grilled monkfish with citrus and herbs. Monkfish is occasionally caught in Guinea''s deeper coastal waters; its firm, lobster-like flesh is prized in Conakry''s fishing community restaurants.', TRUE),
('dorade_royale_grillee_guinean', 'Dorade Royale Grillée', 168, 24.0, 0.0, 8.0, 0.0, 0.0, 300, 400, 'research', ARRAY['dorade royale grillée', 'grilled sea bream', 'bream grillé'], 'seafood', NULL, 1, 'GN', 'Grilled sea bream, one of Guinea''s most premium coastal fish. Sea bream is caught artisanally offshore; whole grilling is the preferred preparation to showcase its sweet delicate flavor.', TRUE),
('poisson_frit_epice_guinean', 'Poisson Frit Épicé', 215, 22.0, 5.0, 12.0, 0.0, 0.5, 250, NULL, 'research', ARRAY['poisson frit épicé', 'spiced fried fish', 'poisson frit'], 'seafood', NULL, 1, 'GN', 'Deep-fried spiced fish with a crispy coating. Frying fish in hot palm or groundnut oil is the most common street food preparation in Guinean coastal towns; sold with spicy dipping sauce.', TRUE),
('poulet_sauce_moyo_guinean', 'Poulet Sauce Moyo', 205, 22.0, 6.0, 10.5, 1.0, 3.5, 300, NULL, 'research', ARRAY['poulet sauce moyo', 'chicken with moyo', 'poulet sauce fraîche'], 'poultry', NULL, 1, 'GN', 'Chicken with moyo sauce — a fresh tomato and herb relish often served cold over hot grilled chicken. Moyo sauce is common in Guinean restaurants as a fresh counterpoint to grilled meats.', TRUE),
('sauce_tomatee_a_la_viande_guinean', 'Sauce Tomatée à la Viande', 165, 16.0, 7.0, 9.0, 1.5, 5.0, 300, NULL, 'research', ARRAY['sauce tomatée à la viande', 'tomato meat sauce', 'sauce tomate viande'], 'meat', NULL, 1, 'GN', 'Rich tomato meat sauce, the foundational sauce of Guinean daily cooking. Used over rice, fonio, or with bread; every Guinean home cook has a personal version of this tomato-meat base.', TRUE),
('boeuf_ndole_guinean', 'Boeuf N''Dolé', 210, 18.0, 6.0, 13.0, 3.0, 1.5, 300, NULL, 'research', ARRAY['boeuf n''dolé', 'beef bitter leaf stew', 'ndolé boeuf'], 'meat', NULL, 1, 'GN', 'Beef with ndolé greens (bitter leaf) in peanut sauce, influenced by Cameroonian cooking through West African trade networks. Common among Guinean communities in border areas.', TRUE),
('poulet_moinmoin_guinean', 'Poulet Moïnmoïn', 195, 18.0, 10.0, 10.0, 2.0, 2.0, 280, NULL, 'research', ARRAY['poulet moïnmoïn', 'chicken with bean cakes', 'poulet moin moin'], 'poultry', NULL, 1, 'GN', 'Chicken with bean pudding (moin moin) — steamed black-eyed pea cakes served with chicken sauce. West African bean pudding accompanies chicken sauce as a complete protein-rich meal.', TRUE),
('boeuf_au_piment_vert_guinean', 'Boeuf au Piment Vert', 220, 22.0, 5.0, 13.0, 1.5, 2.0, 280, NULL, 'research', ARRAY['boeuf au piment vert', 'green chili beef', 'boeuf piment vert'], 'meat', NULL, 1, 'GN', 'Beef braised with fresh green chili peppers. Green chili beef is a Malinké specialty of Guinea''s Haute Guinée region, where fresh chilies are grown abundantly in home gardens.', TRUE),
('pintade_rotie_aux_herbes_guinean', 'Pintade Rôtie aux Herbes', 210, 26.0, 1.0, 11.0, 0.0, 0.5, 280, NULL, 'research', ARRAY['pintade rôtie aux herbes', 'herb guinea fowl', 'pintade thym ail'], 'poultry', NULL, 1, 'GN', 'Herb-roasted guinea fowl with thyme, garlic, and local aromatic plants. Herb-roasted guinea fowl is considered one of Guinea''s finest preparations; it is presented whole at formal dinners.', TRUE),
('agneau_a_la_broche_guinean', 'Agneau à la Broche', 250, 24.0, 0.0, 17.0, 0.0, 0.0, 300, NULL, 'research', ARRAY['agneau à la broche', 'spit-roasted lamb', 'méchoui guinéen'], 'meat', NULL, 1, 'GN', 'Whole spit-roasted lamb, the centerpiece of Tabaski celebrations in Guinea. The entire lamb is skewered and rotated over a wood fire for several hours; every household prepares one for the festival.', TRUE),
('crevettes_moyo_guinean', 'Crevettes Moyo', 138, 20.0, 5.0, 4.5, 1.0, 3.0, 250, NULL, 'research', ARRAY['crevettes moyo', 'shrimp moyo', 'crevettes sauce fraîche'], 'seafood', NULL, 1, 'GN', 'Shrimp with fresh tomato moyo relish. The refreshing tomato-onion relish cuts through the richness of grilled shrimp; a light coastal Conakry preparation popular in warm weather.', TRUE),
('sauce_feuilles_de_baobab_au_poisson_guinean', 'Sauce Feuilles de Baobab au Poisson', 145, 15.0, 7.0, 7.0, 4.0, 1.5, 300, NULL, 'research', ARRAY['sauce feuilles de baobab au poisson', 'baobab leaf fish stew', 'sauce lalo poisson'], 'seafood', NULL, 1, 'GN', 'Dried baobab leaf (lalo) sauce with fish. Baobab leaves are dried and powdered; their mucilaginous quality thickens sauces naturally. This ancient preparation is common in Guinea''s savanna regions.', TRUE),
('poule_au_gingembre_guinean', 'Poule au Gingembre', 185, 22.0, 5.0, 9.0, 0.5, 2.0, 300, NULL, 'research', ARRAY['poule au gingembre', 'ginger chicken hen', 'poule au gingembre frais'], 'poultry', NULL, 1, 'GN', 'Stewed hen in fresh ginger sauce. Free-range hens past laying age are often reserved for this long-simmered preparation; Guinea is a major ginger producer and its fresh ginger is world-class.', TRUE),
('poisson_au_lait_de_coco_guinean', 'Poisson au Lait de Coco', 215, 20.0, 5.0, 13.0, 0.5, 3.0, 300, NULL, 'research', ARRAY['poisson au lait de coco', 'coconut fish', 'poisson coco'], 'seafood', NULL, 1, 'GN', 'Fish in coconut milk sauce, influenced by trading contacts with the Bijagos Islands. Coconut palms grow along Guinea''s coast; coconut milk-based fish preparations are a coastal specialty.', TRUE),
('poulet_grille_au_citron_guinean', 'Poulet Grillé au Citron', 190, 25.0, 2.0, 9.0, 0.0, 1.5, 280, NULL, 'research', ARRAY['poulet grillé au citron', 'lemon grilled chicken', 'poulet citronné'], 'poultry', NULL, 1, 'GN', 'Lemon-marinated grilled chicken. Marinating chicken in citrus is widespread across Guinea''s diverse ethnic groups; the acid tenderizes the lean free-range birds while adding brightness.', TRUE),
('anguille_fumee_en_sauce_guinean', 'Anguille Fumée en Sauce', 185, 18.0, 4.0, 11.0, 1.0, 2.0, 250, NULL, 'research', ARRAY['anguille fumée en sauce', 'smoked eel sauce', 'anguille fumée'], 'seafood', NULL, 1, 'GN', 'Smoked freshwater eel in spiced sauce. Eels are found in Guinea''s rivers and are traditionally smoked; this preparation is a specialty of Kissi and Kpelle river communities.', TRUE),
('requin_braise_guinean', 'Requin Braisé', 172, 28.0, 0.0, 6.5, 0.0, 0.0, 300, NULL, 'research', ARRAY['requin braisé', 'braised shark', 'requin grillé'], 'seafood', NULL, 1, 'GN', 'Braised shark steak, caught by Guinean artisanal fishermen. Shark (primarily small species) is consumed along Guinea''s coast; it has firm, mild flesh that benefits from strong marinades.', TRUE),
('cuisse_de_grenouille_sautee_guinean', 'Cuisse de Grenouille Sautée', 132, 20.0, 2.0, 5.0, 0.0, 0.5, 200, 30, 'research', ARRAY['cuisse de grenouille sautée', 'frog legs', 'grenouilles sautées'], 'game', NULL, 1, 'GN', 'Sautéed frog legs with garlic and herbs, a delicacy in Guinea''s forest region. Frogs are gathered from rice paddies and rivers; their consumption reflects forest region Guineans'' broad protein repertoire.', TRUE),
('escargots_en_sauce_tomate_guinean', 'Escargots en Sauce Tomate', 115, 18.0, 4.0, 3.5, 0.5, 2.0, 250, NULL, 'research', ARRAY['escargots en sauce tomate', 'giant snail stew', 'achatines sauce tomate'], 'game', NULL, 1, 'GN', 'Giant African land snails (escargots géants) in tomato sauce. Giant snails are harvested during the rainy season in Guinea''s forests; they are a traditional protein source for forest communities.', TRUE),
('termites_frits_insectes_guinean', 'Termites Frits (Insectes)', 348, 28.0, 8.0, 28.0, 5.0, 0.0, 50, NULL, 'research', ARRAY['termites frits (insectes)', 'fried termites', 'fourmis blanches frites'], 'traditional', NULL, 1, 'GN', 'Fried flying termites (white ants), collected during the first rains. In Guinea''s forest region, communities gather swarming termites by lamplight; fried termites are a seasonal protein-dense snack.', TRUE),
('chenilles_grillees_guinean', 'Chenilles Grillées', 290, 25.0, 5.0, 22.0, 4.0, 0.5, 50, NULL, 'research', ARRAY['chenilles grillées', 'edible caterpillars', 'larves grillées'], 'traditional', NULL, 1, 'GN', 'Grilled edible caterpillars collected from forest trees. Caterpillar consumption is documented among Guinea''s forest communities; they are rich in protein and fat and sold dried in forest markets.', TRUE),
('pintade_sauce_graine_guinean', 'Pintade Sauce Graine', 270, 22.0, 5.0, 19.0, 1.5, 1.0, 300, NULL, 'research', ARRAY['pintade sauce graine', 'guinea fowl palm kernel', 'pintade sauce noix palme'], 'poultry', NULL, 1, 'GN', 'Guinea fowl braised in palm kernel cream sauce. Combining the prestige bird (guinea fowl) with the labor-intensive palm kernel sauce creates the most prestigious everyday dish in forest Guinea.', TRUE),
('lieu_jaune_grille_guinean', 'Lieu Jaune Grillé', 158, 24.0, 0.0, 7.0, 0.0, 0.0, 280, NULL, 'research', ARRAY['lieu jaune grillé', 'grilled yellowfin', 'lieu grillé'], 'seafood', NULL, 1, 'GN', 'Grilled yellowfin (lieu jaune) caught in coastal Guinea. A prized fresh catch sold at morning fish markets; simply grilled over charcoal to preserve the natural sweet flavor.', TRUE),
('boeuf_hache_sauce_gombo_guinean', 'Boeuf Haché Sauce Gombo', 195, 18.0, 7.0, 11.0, 3.0, 2.0, 300, NULL, 'research', ARRAY['boeuf haché sauce gombo', 'ground beef okra', 'boeuf haché gombo'], 'meat', NULL, 1, 'GN', 'Ground beef okra stew. Mincing beef makes it affordable and allows it to distribute throughout the okra sauce; this everyday preparation is economical and protein-rich.', TRUE),
('cabri_roti_guinean', 'Cabri Rôti', 220, 24.0, 0.0, 13.0, 0.0, 0.0, 280, NULL, 'research', ARRAY['cabri rôti', 'whole roast goat', 'méchoui de cabri'], 'meat', NULL, 1, 'GN', 'Whole roasted goat, the centerpiece of Guinean weddings and naming ceremonies. The whole goat is rubbed with spice paste and slow-roasted over a wood fire; communal roasting is a social event.', TRUE),
('poisson_au_four_guinean', 'Poisson au Four', 170, 24.0, 2.0, 7.5, 0.5, 1.0, 300, NULL, 'research', ARRAY['poisson au four', 'baked fish', 'poisson baked'], 'seafood', NULL, 1, 'GN', 'Oven-baked fish stuffed with herbs and vegetables. Baking fish in clay ovens was common in Guinea before modern gas cooking; the enclosed heat creates a moist, aromatic result.', TRUE),
('sauce_de_clams_guinean', 'Sauce de Clams', 145, 16.0, 6.0, 6.5, 0.5, 2.0, 300, NULL, 'research', ARRAY['sauce de clams', 'clam stew', 'palourdes en sauce'], 'seafood', NULL, 1, 'GN', 'Clam stew in tomato sauce. Clams are harvested from Guinea''s sandy coastal beaches and estuaries; they cook quickly and are a source of affordable shellfish protein for coastal communities.', TRUE),
('boeuf_laque_piment_guinean', 'Boeuf Laqué Piment', 235, 24.0, 5.0, 14.0, 0.5, 3.0, 250, NULL, 'research', ARRAY['boeuf laqué piment', 'spicy glazed beef', 'boeuf laqué pimenté'], 'meat', NULL, 1, 'GN', 'Glazed spicy beef, marinated in chili-honey glaze and roasted. A restaurant adaptation found in Conakry''s urban eateries, blending traditional spicing with a sweet glaze technique.', TRUE),
('saumon_du_nil_grille_guinean', 'Saumon du Nil Grillé', 195, 22.0, 0.0, 12.0, 0.0, 0.0, 300, NULL, 'research', ARRAY['saumon du nil grillé', 'nile tilapia grilled', 'tilapia du nil'], 'seafood', NULL, 1, 'GN', 'Grilled Nile tilapia (often marketed as Nile salmon in Guinea). The large plump tilapia from Guinea''s rivers are considered the best quality; simple grilling preserves their mild sweet flavor.', TRUE),
('ragout_marin_conakry_guinean', 'Ragoût Marin Conakry', 175, 18.0, 7.0, 8.5, 1.5, 3.0, 350, NULL, 'research', ARRAY['ragoût marin conakry', 'conakry seafood stew', 'bouillabaisse guinéenne'], 'seafood', NULL, 1, 'GN', 'Conakry-style mixed seafood stew with shrimp, clams, and fish in spiced tomato broth. A restaurant dish reflecting Conakry''s position as a coastal capital with access to diverse marine resources.', TRUE),
('poulet_sauce_moutarde_locale_guinean', 'Poulet Sauce Moutarde Locale', 200, 22.0, 5.0, 10.5, 0.5, 2.5, 300, NULL, 'research', ARRAY['poulet sauce moutarde locale', 'chicken dawadawa sauce', 'poulet moutarde locale'], 'poultry', NULL, 1, 'GN', 'Chicken in local mustard sauce using dawadawa (locust bean) as the pungent element instead of European mustard. A pre-colonial mustard-substitute tradition in Guinea''s interior.', TRUE),
('viande_de_chevreuil_guinean', 'Viande de Chevreuil', 172, 28.0, 0.0, 6.5, 0.0, 0.0, 250, NULL, 'research', ARRAY['viande de chevreuil', 'venison', 'viande de biche africaine'], 'game', NULL, 1, 'GN', 'Venison from small forest deer, a traditional game meat in Guinea''s highlands and forest zones. Guinea''s duiker species are the most commonly hunted; the lean dark meat is prized for its flavor.', TRUE),
('poisson_seche_bouilli_guinean', 'Poisson Séché Bouilli', 162, 26.0, 0.0, 6.0, 0.0, 0.0, 150, NULL, 'research', ARRAY['poisson séché bouilli', 'boiled dried fish', 'poisson sec bouilli'], 'seafood', NULL, 1, 'GN', 'Rehydrated dried fish simmered in seasoned water until tender. The simple boiling of dried fish rehydrates and softens it before use in more complex preparations; sold as ready-to-eat in markets.', TRUE),
('poulet_sauce_baobab_guinean', 'Poulet Sauce Baobab', 188, 21.0, 6.0, 9.5, 2.0, 2.0, 300, NULL, 'research', ARRAY['poulet sauce baobab', 'chicken baobab sauce', 'poulet lalo'], 'poultry', NULL, 1, 'GN', 'Chicken in baobab leaf sauce, unique to Guinea''s northern savanna. The powdered baobab leaves give a mild, slightly sour tang and thick consistency; this dish is found in Labé prefecture.', TRUE),
('mouton_grille_whole_guinean', 'Mouton Grillé Whole', 255, 23.0, 0.0, 18.0, 0.0, 0.0, 300, NULL, 'research', ARRAY['mouton grillé whole', 'grilled mutton', 'mouton braisé'], 'meat', NULL, 1, 'GN', 'Grilled mutton pieces over charcoal. Mutton cuts (côtes, gigot) are grilled and sold at Guinean maquis as the definitive celebration meat, especially after Friday prayers.', TRUE),
('poisson_au_four_a_la_marocaine_guinean', 'Poisson au Four à la Marocaine', 178, 23.0, 4.0, 8.5, 1.0, 2.0, 300, NULL, 'research', ARRAY['poisson au four à la marocaine', 'chermoula baked fish', 'poisson chermoula'], 'seafood', NULL, 1, 'GN', 'Moroccan-influenced baked fish with chermoula herbs — cumin, coriander, garlic, and lemon. North African culinary influence came to Guinea through trans-Saharan trade and Islamic scholarship routes.', TRUE),
('mafe_digname_au_poulet_guinean', 'Mafé d''Igname au Poulet', 230, 16.0, 18.0, 12.0, 2.5, 3.0, 400, NULL, 'research', ARRAY['mafé d''igname au poulet', 'yam chicken maafe', 'mafé igname'], 'traditional', NULL, 1, 'GN', 'Chicken and yam groundnut stew. Adding yam pieces to maafe is a forest region variation that stretches the dish further while adding hearty starch; popular in Nzérékoré.', TRUE),
('crevettes_crustacees_au_four_guinean', 'Crevettes Crustacées au Four', 148, 20.0, 3.0, 6.0, 0.0, 1.0, 250, NULL, 'research', ARRAY['crevettes crustacées au four', 'baked shell-on shrimp', 'crevettes au four'], 'seafood', NULL, 1, 'GN', 'Baked whole shrimp in shell with herbs. Baking shrimp in their shells retains moisture and imparts a deeper crustacean flavor; popular in Conakry''s home kitchens.', TRUE),
('sauce_forestiere_viande_guinean', 'Sauce Forestière Viande', 220, 18.0, 8.0, 14.0, 3.0, 2.0, 350, NULL, 'research', ARRAY['sauce forestière viande', 'forest meat sauce', 'sauce du forestier'], 'traditional', NULL, 1, 'GN', 'Forest-style mixed meat sauce with wild mushrooms and forest herbs. A specialty of Guinea''s N''Zérékoré forest region, blending multiple protein sources with foraged forest ingredients.', TRUE),
('poulet_a_la_moutarde_dijonaise_guinean', 'Poulet à la Moutarde Dijonaise', 210, 23.0, 4.0, 11.0, 0.0, 1.5, 300, NULL, 'research', ARRAY['poulet à la moutarde dijonaise', 'dijon chicken', 'poulet moutarde à la française'], 'poultry', NULL, 1, 'GN', 'Chicken in Dijon-style mustard cream sauce, a French colonial culinary legacy maintained in Guinea''s upscale dining establishments. Adapted with local cream substitutes.', TRUE),
('boeuf_tikka_guineen_guinean', 'Boeuf Tikka Guinéen', 225, 26.0, 5.0, 11.0, 0.5, 2.0, 250, NULL, 'research', ARRAY['boeuf tikka guinéen', 'lebanese-style beef', 'boeuf mariné épicé'], 'meat', NULL, 1, 'GN', 'Spiced marinated grilled beef influenced by Lebanese cooking. Guinea''s Lebanese diaspora community has influenced Conakry''s restaurant culture; spiced marinated beef is a shared culinary tradition.', TRUE),
('sauce_feuilles_de_patate_douce_au_boeuf_guinean', 'Sauce Feuilles de Patate Douce au Boeuf', 185, 17.0, 8.0, 10.0, 3.5, 2.5, 300, NULL, 'research', ARRAY['sauce feuilles de patate douce au boeuf', 'sweet potato leaf beef', 'feuilles patate boeuf'], 'traditional', NULL, 1, 'GN', 'Sweet potato leaf sauce with beef chunks and palm oil. The sweet potato leaves are pounded before cooking to soften them; this iron-rich stew is considered very nourishing.', TRUE),
('poisson_sauce_gambari_guinean', 'Poisson Sauce Gambari', 165, 20.0, 5.0, 7.5, 1.0, 2.0, 300, NULL, 'research', ARRAY['poisson sauce gambari', 'gambari fish sauce', 'poisson sauce crevettes séchées'], 'seafood', NULL, 1, 'GN', 'Fish in gambari sauce — a dried shrimp and spice paste sauce used in northeastern Guinea. Gambari (from Hausa) refers to the dried shrimp seasoning essential to many northern Guinean fish preparations.', TRUE),
('ragout_de_poulet_aux_ignames_guinean', 'Ragoût de Poulet aux Ignames', 210, 16.0, 18.0, 8.0, 2.0, 2.0, 400, NULL, 'research', ARRAY['ragoût de poulet aux ignames', 'chicken yam stew', 'ragoût poulet igname'], 'traditional', NULL, 1, 'GN', 'Chicken and yam stew, a hearty forest region one-pot meal. Yams are a prestige food in Guinea''s southern forests; combining them with chicken creates a complete ceremonial dish.', TRUE),
('pintade_fumee_sauce_tomate_guinean', 'Pintade Fumée Sauce Tomate', 208, 25.0, 5.0, 10.0, 1.0, 3.0, 300, NULL, 'research', ARRAY['pintade fumée sauce tomate', 'smoked guinea fowl', 'pintade fumée sauce'], 'poultry', NULL, 1, 'GN', 'Smoked guinea fowl rehydrated in fresh tomato sauce with onions. Smoking guinea fowl preserves it for days; the resulting stew has an intensely savory smoky character prized in rural Guinea.', TRUE),
('poulet_sauce_gombo_forestier_guinean', 'Poulet Sauce Gombo Forestier', 185, 20.0, 7.0, 9.5, 3.0, 2.0, 350, NULL, 'research', ARRAY['poulet sauce gombo forestier', 'forest chicken okra', 'poulet gombo forêt'], 'poultry', NULL, 1, 'GN', 'Forest-style chicken okra stew enriched with smoked fish and palm oil. The forest region (Guinée Forestière) version adds both fresh and smoked proteins for layered umami depth.', TRUE),
('boeuf_sauce_graine_fouta_guinean', 'Boeuf Sauce Graine Fouta', 275, 19.0, 5.0, 21.0, 2.0, 1.0, 300, NULL, 'research', ARRAY['boeuf sauce graine fouta', 'fouta beef palm sauce', 'boeuf sauce noix fouta'], 'meat', NULL, 1, 'GN', 'Beef in palm kernel cream sauce from the Fouta Djallon highlands. Fula herding communities combine their highland cattle beef with traded palm nuts from the coast in this celebratory stew.', TRUE),
('capitaine_sauce_arachide_guinean', 'Capitaine Sauce Arachide', 248, 22.0, 8.0, 15.0, 2.0, 3.0, 350, NULL, 'research', ARRAY['capitaine sauce arachide', 'capitaine peanut sauce', 'perche arachide'], 'seafood', NULL, 1, 'GN', 'Nile perch in groundnut sauce. This riverside preparation marries the prized capitaine fish with the inland groundnut sauce tradition; a crossover dish between coastal and interior cuisines.', TRUE),
('soupe_epicee_de_crevettes_guinean', 'Soupe Épicée de Crevettes', 138, 18.0, 6.0, 5.0, 1.5, 2.5, 400, NULL, 'research', ARRAY['soupe épicée de crevettes', 'spicy shrimp soup', 'soupe pimentée crevettes'], 'soups', NULL, 1, 'GN', 'Spicy shrimp broth with chili, ginger, and lemon grass. A light but fiery soup served in Conakry''s coastal neighborhoods; the broth is made from shrimp shells for deep seafood flavor.', TRUE),
('veau_en_sauce_tomate_guinean', 'Veau en Sauce Tomate', 195, 22.0, 6.0, 9.5, 1.0, 4.0, 300, NULL, 'research', ARRAY['veau en sauce tomate', 'veal tomato stew', 'veau sauce tomate'], 'meat', NULL, 1, 'GN', 'Veal in tomato sauce, available in Conakry''s upmarket butcher shops and restaurants. Young calf meat is more tender and mild than adult beef; it is prepared for refined urban dining.', TRUE),
('tilapia_sauce_palme_rouge_guinean', 'Tilapia Sauce Palme Rouge', 240, 20.0, 4.0, 16.0, 1.0, 1.5, 300, NULL, 'research', ARRAY['tilapia sauce palme rouge', 'tilapia red palm oil', 'tilapia huile de palme'], 'seafood', NULL, 1, 'GN', 'Tilapia cooked in red palm oil sauce with tomatoes and onions. The vibrant red palm oil lends both color and distinctive flavor; this simple preparation is a weekday staple along Guinea''s rivers.', TRUE),
('poulet_sauce_noir_conakry_guinean', 'Poulet Sauce Noir Conakry', 215, 22.0, 6.0, 11.0, 1.0, 2.5, 300, NULL, 'research', ARRAY['poulet sauce noir conakry', 'conakry dark chicken sauce', 'sauce noire poulet'], 'poultry', NULL, 1, 'GN', 'Conakry-style dark chicken sauce made from caramelized onions and whole spices cooked until deeply browned. The dark colour comes from long-cooked onions, not dark roux; a neighborhood classic.', TRUE),
('crevettes_sauce_mafe_guinean', 'Crevettes Sauce Mafé', 228, 19.0, 8.0, 14.0, 2.0, 3.5, 300, NULL, 'research', ARRAY['crevettes sauce mafé', 'shrimp maafe', 'crevettes arachide'], 'seafood', NULL, 1, 'GN', 'Shrimp in groundnut sauce. Combining shrimp with peanut sauce bridges Guinea''s coastal and interior culinary traditions; the creamy sauce complements the sweet shellfish perfectly.', TRUE),
('mouton_mijote_cannelle_guinean', 'Mouton Mijoté Cannelle', 235, 20.0, 4.0, 15.0, 0.5, 2.0, 300, NULL, 'research', ARRAY['mouton mijoté cannelle', 'cinnamon mutton', 'mouton cannelle'], 'meat', NULL, 1, 'GN', 'Mutton slow-cooked with cinnamon and North African spices, reflecting trans-Saharan trade influence on Guinean cooking. This aromatic preparation is found in Conakry''s Muslim communities.', TRUE),
('cuisse_de_poulet_braisee_guinean', 'Cuisse de Poulet Braisée', 215, 24.0, 3.0, 12.0, 0.0, 1.0, 250, 200, 'research', ARRAY['cuisse de poulet braisée', 'braised chicken thigh', 'cuisse de poulet sauce'], 'poultry', NULL, 1, 'GN', 'Braised chicken drumstick and thigh in onion-tomato sauce. Chicken pieces braised separately allow home cooks to serve individual portions; the dark meat legs are considered most flavorful.', TRUE),
('poisson_mariniere_guinean', 'Poisson Marinière', 162, 24.0, 3.0, 6.5, 0.5, 1.5, 300, NULL, 'research', ARRAY['poisson marinière', 'marinière fish', 'poisson au vin blanc'], 'seafood', NULL, 1, 'GN', 'Fish poached in white wine, onion, and herb broth, a French-colonial preparation adapted with local fish. Found in Guinea''s colonial-era restaurants and still served in Conakry''s older establishments.', TRUE),
('albondigas_de_viande_guinean', 'Albondigas de Viande', 205, 18.0, 8.0, 12.0, 1.0, 3.0, 250, 35, 'research', ARRAY['albondigas de viande', 'meatballs tomato sauce', 'boulettes de viande'], 'meat', NULL, 1, 'GN', 'Meat meatballs in tomato sauce, influenced by Portuguese-Guinean colonial cuisine. Meatballs are sold at Conakry snack bars and increasingly in Guinea''s growing fast-casual restaurant scene.', TRUE),
('soupe_de_crabe_guinean', 'Soupe de Crabe', 128, 14.0, 5.0, 5.5, 0.5, 1.5, 400, NULL, 'research', ARRAY['soupe de crabe', 'crab broth', 'bouillon de crabe'], 'soups', NULL, 1, 'GN', 'Crab broth with vegetables, simmered from whole Atlantic crabs. Guinea''s mangrove estuaries yield abundant crabs; the broth is strained and served as a restorative coastal soup.', TRUE),
('boeuf_seche_soupe_fouta_guinean', 'Boeuf Séché Soupe Fouta', 155, 18.0, 5.0, 7.0, 1.0, 1.5, 350, NULL, 'research', ARRAY['boeuf séché soupe fouta', 'dried beef soup', 'soupe boeuf séché fouta'], 'soups', NULL, 1, 'GN', 'Soup made from rehydrated dried beef with vegetables. In the Fouta Djallon highlands where drying beef is a preservation tradition, this soup uses stored dried meat during the dry season.', TRUE),
('maquereau_fume_sauce_guinean', 'Maquereau Fumé Sauce', 210, 22.0, 4.0, 12.0, 1.0, 2.0, 250, NULL, 'research', ARRAY['maquereau fumé sauce', 'smoked mackerel sauce', 'maquereau fumé sauce tomate'], 'seafood', NULL, 1, 'GN', 'Smoked mackerel in tomato-onion sauce. Atlantic mackerel smokes extremely well due to its high fat content; smoked mackerel sauce is a common weekday fish preparation across coastal Guinea.', TRUE),
('boeuf_sauce_gombo_malinke_guinean', 'Boeuf Sauce Gombo Malinké', 190, 18.0, 7.0, 10.5, 3.0, 2.0, 350, NULL, 'research', ARRAY['boeuf sauce gombo malinké', 'malinké beef okra', 'boeuf gombo soumbara'], 'meat', NULL, 1, 'GN', 'Malinké-style beef okra stew from Haute Guinée. The Malinké version of okra stew uses fermented locust bean (soumbara) for an additional umami layer alongside the beef.', TRUE),
('poule_locale_fonio_guinean', 'Poule Locale Fonio', 210, 18.0, 20.0, 7.0, 1.5, 1.0, 400, NULL, 'research', ARRAY['poule locale fonio', 'local hen with fonio', 'poule fonio'], 'traditional', NULL, 1, 'GN', 'Free-range local hen served with steamed fonio. This dish represents Guinea''s national identity — the free-range local chicken and indigenous fonio grain are both symbols of Guinean culinary heritage.', TRUE),
('ragout_de_lamantin_guinean', 'Ragoût de Lamantin', 178, 25.0, 2.0, 8.0, 0.0, 0.5, 250, NULL, 'research', ARRAY['ragoût de lamantin', 'manatee stew', 'viande de lamantin'], 'game', NULL, 1, 'GN', 'Manatee stew, historically consumed by river communities in Guinea. Now legally protected, manatee was traditionally hunted along Guinea''s rivers; this entry documents a historical food practice.', TRUE),
('boeuf_sauce_soumbara_guinean', 'Boeuf Sauce Soumbara', 200, 20.0, 5.0, 11.0, 1.0, 1.5, 300, NULL, 'research', ARRAY['boeuf sauce soumbara', 'locust bean beef sauce', 'boeuf dawadawa'], 'meat', NULL, 1, 'GN', 'Beef in fermented locust bean (soumbara/dawadawa) sauce. Soumbara is Guinea''s indigenous umami seasoning; its pungent fermented flavor enriches beef stews throughout the Mande-speaking regions.', TRUE),
('grillades_mixtes_guineennes_guinean', 'Grillades Mixtes Guinéennes', 240, 26.0, 2.0, 14.0, 0.0, 1.0, 300, NULL, 'research', ARRAY['grillades mixtes guinéennes', 'mixed grill platter', 'plateau grillades'], 'traditional', NULL, 1, 'GN', 'Mixed grill platter of beef, lamb, chicken, and merguez sausage. Urban Guinean maquis (open-air restaurants) serve mixed grill platters as the house specialty for groups celebrating.', TRUE),
('poisson_sauce_citron_coriandre_guinean', 'Poisson Sauce Citron Coriandre', 160, 24.0, 3.0, 6.5, 0.5, 1.5, 280, NULL, 'research', ARRAY['poisson sauce citron coriandre', 'lemon coriander fish', 'poisson coriandre'], 'seafood', NULL, 1, 'GN', 'Fish in lemon-coriander sauce, a light preparation popular in Conakry''s upscale restaurants. Coriander (cilantro) is grown in Guinea''s gardens; its fresh fragrance lifts simple fish preparations.', TRUE),
('soupe_legumes_viande_fouta_guinean', 'Soupe Légumes Viande Fouta', 148, 14.0, 9.0, 6.0, 3.0, 3.5, 400, NULL, 'research', ARRAY['soupe légumes viande fouta', 'fouta highland soup', 'soupe montagnarde'], 'soups', NULL, 1, 'GN', 'Highland vegetable meat soup from the Fouta Djallon, rich in mountain vegetables including cabbage, turnips, and carrots alongside beef. Highland Fula cooking emphasizes vegetable abundance.', TRUE),
('boeuf_hache_sauce_poivre_guinean', 'Boeuf Haché Sauce Poivre', 218, 20.0, 4.0, 13.0, 0.5, 1.5, 250, NULL, 'research', ARRAY['boeuf haché sauce poivre', 'pepper sauce beef', 'steak haché sauce poivre'], 'meat', NULL, 1, 'GN', 'Ground beef in black pepper cream sauce, a French-influenced preparation found in urban Guinean bistros. Black pepper (poivre) sauce adopted from French cuisine is made with local cream substitute.', TRUE),
